examples.original_ir:
define <2 x ptr> @test_select_eq(<2 x ptr> %p, <2 x ptr> %q) {
  %cmp = icmp eq <2 x ptr> %p, %q
  %sel = select <2 x i1> %cmp, <2 x ptr> %p, <2 x ptr> %q
  ret <2 x ptr> %sel
}

examples.optimized_ir:
define <2 x ptr> @test_select_eq(<2 x ptr> %p, <2 x ptr> %q) {
  ret <2 x ptr> %q
}
